export const VALIDATE_WRITE_LEASE_SCRIPT = String.raw`#!/usr/bin/env node
// Generated by Truthmark. Rerun truthmark init after upgrades.
import fs from "node:fs";
import process from "node:process";

const helper = "validate-write-lease";

const print = (payload) => {
  process.stdout.write(JSON.stringify(payload, null, 2) + "\n");
};

const fail = (errors) => {
  print({ ok: false, helper, errors });
  process.exit(1);
};

const args = process.argv.slice(2);
if (args.length !== 2) {
  fail(["expected lease/report file and changed-files file arguments"]);
}

const readText = (filePath, label) => {
  try {
    return fs.readFileSync(filePath, "utf8");
  } catch (error) {
    fail(["could not read " + label + ": " + error.message]);
  }
};

const normalizePath = (value) => value.trim().replace(/^["']|["']$/g, "").replace(/^\.\//, "").replace(/^\//, "");

const parseListFields = (text) => {
  const lists = { allowedWrites: [], forbiddenWrites: [] };
  let current = null;

  for (const rawLine of text.split(/\r?\n/)) {
    const sectionMatch = rawLine.match(/^([A-Za-z][A-Za-z0-9_-]*):\s*(.*)$/);
    if (sectionMatch !== null) {
      current = Object.prototype.hasOwnProperty.call(lists, sectionMatch[1])
        ? sectionMatch[1]
        : null;

      const inlineValue = sectionMatch[2].trim();
      if (current !== null && inlineValue !== "" && inlineValue !== "[]") {
        lists[current].push(inlineValue);
      }
      continue;
    }

    const itemMatch = rawLine.match(/^\s*-\s+(.+)\s*$/);
    if (current !== null && itemMatch !== null) {
      lists[current].push(itemMatch[1].trim());
      continue;
    }

    if (rawLine.trim() !== "" && !rawLine.startsWith(" ") && !rawLine.startsWith("\t")) {
      current = null;
    }
  }

  return lists;
};

const isSupportedPattern = (pattern) => {
  const withoutTrailingGlob = pattern.endsWith("/**") ? pattern.slice(0, -3) : pattern;
  return !/[?*[\]{}]/.test(withoutTrailingGlob);
};

const matchesPattern = (filePath, pattern) => {
  if (pattern.endsWith("/**")) {
    const prefix = pattern.slice(0, -3).replace(/\/+$/, "");
    return filePath === prefix || filePath.startsWith(prefix + "/");
  }

  return filePath === pattern;
};

const leaseText = readText(args[0], "lease/report file");
const changedText = readText(args[1], "changed-files file");
const parsed = parseListFields(leaseText);
const allowedWrites = parsed.allowedWrites.map(normalizePath).filter(Boolean);
const forbiddenWrites = parsed.forbiddenWrites.map(normalizePath).filter(Boolean);
const changedFiles = changedText.split(/\r?\n/).map(normalizePath).filter(Boolean);
const checks = [];
const errors = [];

for (const pattern of [...allowedWrites, ...forbiddenWrites]) {
  if (!isSupportedPattern(pattern)) {
    errors.push("manual-validation required: unsupported write pattern " + pattern);
  }
}

if (allowedWrites.length === 0) {
  errors.push("manual-validation required: no allowedWrites entries found");
}

if (errors.length === 0) {
  for (const filePath of changedFiles) {
    if (!allowedWrites.some((pattern) => matchesPattern(filePath, pattern))) {
      errors.push(filePath + " is outside allowedWrites");
      continue;
    }

    const forbiddenPattern = forbiddenWrites.find((pattern) => matchesPattern(filePath, pattern));
    if (forbiddenPattern !== undefined) {
      errors.push(filePath + " matches forbiddenWrites pattern " + forbiddenPattern);
      continue;
    }

    checks.push(filePath);
  }
}

if (errors.length > 0) {
  fail(errors);
}

print({ ok: true, helper, checks });
`;
